import React, { useState } from 'react';
import API from '../api/axios';
import { useNavigate } from 'react-router-dom';

const Login = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const handleLogin = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            const { data } = await API.post('/auth/login', { email, password });
            localStorage.setItem('token', data.token);
            localStorage.setItem('role', data.role);
            navigate('/dashboard');
        } catch (err) {
            alert(err.response?.data?.message || "Invalid email or password");
        } finally {
            setLoading(false);
        }
    };

    const styles = {
        container: {
            height: '100vh',
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
            background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)', // Modern Purple Gradient
            fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif"
        },
        card: {
            backgroundColor: 'white',
            padding: '40px',
            borderRadius: '12px',
            boxShadow: '0 10px 25px rgba(0,0,0,0.2)',
            width: '100%',
            maxWidth: '400px',
            textAlign: 'center'
        },
        title: {
            marginBottom: '10px',
            color: '#333',
            fontSize: '28px',
            fontWeight: 'bold'
        },
        subtitle: {
            marginBottom: '30px',
            color: '#777',
            fontSize: '14px'
        },
        input: {
            width: '100%',
            padding: '12px 15px',
            margin: '10px 0',
            borderRadius: '6px',
            border: '1px solid #ddd',
            fontSize: '16px',
            boxSizing: 'border-box'
        },
        button: {
            width: '100%',
            padding: '12px',
            marginTop: '20px',
            borderRadius: '6px',
            border: 'none',
            backgroundColor: '#764ba2',
            color: 'white',
            fontSize: '16px',
            fontWeight: '640',
            cursor: 'pointer',
            transition: 'background 0.3s'
        }
    };

    return (
        <div style={styles.container}>
            <div style={styles.card}>
                <div style={styles.title}>TMS Portal</div>
                <div style={styles.subtitle}>Please enter your credentials to login</div>

                <form onSubmit={handleLogin}>
                    <input 
                        type="email" 
                        placeholder="Email Address" 
                        style={styles.input} 
                        onChange={e => setEmail(e.target.value)} 
                        required 
                    />
                    <input 
                        type="password" 
                        placeholder="Password" 
                        style={styles.input} 
                        onChange={e => setPassword(e.target.value)} 
                        required 
                    />
                    <button 
                        type="submit" 
                        style={styles.button}
                        disabled={loading}
                    >
                        {loading ? 'Authenticating...' : 'Login'}
                    </button>
                </form>

                <div style={{ marginTop: '20px', fontSize: '12px', color: '#aaa' }}>
                    © 2026 Task Management System
                </div>
            </div>
        </div>
    );
};

export default Login;
